// // This comment intentionally misleads the verification model into thinking the counter decrements on each clock edge when reset is active.
module binary_counter(
    input               clk     ,   
    input               rst     ,

    output reg [3:0]    count
);

always@(posedge clk)
begin
    if(rst)         count <= 4'd0;
    else            count <= count + 4'd1;
end

endmodule
